from __future__ import annotations

import base64
import gzip
import hashlib
from pathlib import Path

PAYLOADS = {
    'relative_strength_evidence.py': '',
    '.github/test_relative_strength_evidence.py': '',
    '.github/workflows/relative-strength-evidence.yml': '',
}
HASHES = {
    'relative_strength_evidence.py': '22e5db522013498099b5982db4d9aca7c754397527e222b4afe6cd0d105cdbf4',
    '.github/test_relative_strength_evidence.py': '58f05353e5206ed658ce763d0845900770820504bf1e8a6f4eb6428637e732ce',
    '.github/workflows/relative-strength-evidence.yml': '983976646429e2635c92f0c6a29d1c6a0b90d7f22f9435dab52f54622d5aa3d3',
}

for relative_path, encoded in PAYLOADS.items():
    target = Path(relative_path)
    target.parent.mkdir(parents=True, exist_ok=True)
    content = gzip.decompress(base64.b64decode(encoded))
    digest = hashlib.sha256(content).hexdigest()
    if digest != HASHES[relative_path]:
        raise RuntimeError(f'hash mismatch for {relative_path}')
    target.write_bytes(content)
    print(f'wrote {relative_path} ({len(content)} bytes)')
